sql:
SELECT AVG(speed) 
FROM track_data 
WHERE is_active = 1;

SELECT timestamp
FROM track_data
WHERE object_type = 'AV';

SELECT AVG(speed) AS average_speed
FROM track_data
WHERE object_type = 'AV' AND city_id = 1;

SELECT DISTINCT object_type
FROM track_data
ORDER BY object_type;

SELECT AVG(speed) AS average_pace_of_life
FROM track_data
WHERE city_id = (SELECT city_id FROM cities WHERE city_name = 'Pittsburgh');

SELECT DISTINCT object_type
FROM track_data
WHERE city_id = 1;

SELECT average_speed
FROM traffic_analysis
WHERE city_id = 0 AND date = '2023-01-01';

SELECT COUNT(DISTINCT track_id) 
FROM track_data 
WHERE city_id = 1;

SELECT AVG(congestion_index) AS avg_congestion_index, AVG(average_speed) AS avg_average_speed
FROM traffic_analysis
WHERE city_id = (SELECT city_id FROM cities WHERE city_name = 'Pittsburgh');

external_knowledge:
Active objects refer to those with 'is_active' status set to 1; 
Location is characterized by 'x_position' and 'y_position'; 
Observation methods are indicated by 'data_source_name'.

sql:
SELECT SUM(speed) AS total_speed
FROM track_data
WHERE track_id = '0' AND city_id = 1;

SELECT city_id, AVG(speed) AS average_speed
FROM track_data
GROUP BY city_id;
